import java.util.*;
import java.util.stream.*;

public class Earth
{
	private static List<String> countries;
	private static final int MIN_CHARS = 5;

	public static void main(final String[] args)
	{
		// Countries that start with 'B' or 'C' in lowercase, sorted by length
		List<String> result = countries.stream()
				.filter(c -> c != null && (c.toLowerCase().startsWith("b") || c.toLowerCase().startsWith("c")))
				.sorted(Comparator.comparingInt(String::length))
				.toList();
		System.out.println(result);

		// Print in reverse all countries that end with 'y' or 'Y'
		countries.stream()
		.filter(c -> c != null && (c.endsWith("y") || c.endsWith("Y")))
		.sorted(Comparator.reverseOrder())
		.forEach(System.out::println);
	}

	// Method returning filtered stream
	public static Stream<String> getStream(List<String> list)
	{
		return list.stream()
			.filter(s -> s != null !s.isBlank() && s.length() >= 5);
	}
}

