/**
* This class represents a Dog. Showing it's name and year of birth.
*
* @author 
* @version
**/
public class Dog
{
	private final String name;
	private final int yearOfBirth

	/**
	* Constructor for the Dog.
	*
	* @param name is a String
	* @param yearOfBirth is an int
	**/
	public Dog(final String name, final int yearOfBirth)
	{
		setName(name);
		setYearOfBirth(yearOfBirth);
	}

	/**
	* Setter and validator for the name.
	*
	* @param name is a String
	**/
	public void setName(final String name)
	{
		if (name == null || name.isEmpty())
		{
			throw new IllegalArgumentException("Invalid name");
		}

		this.name = name;
	}

	/**
	* Setter and validator for the year of birth.
	*
	* @param yearOfBirth is an int
	**/
	public void setYearOfBirth(final int yearOfBirth)
	{
		if (yearOfBirth >= 2027)
		{
			throw new IllegalArgumentException("Invalid year of birth");
		}

		this.yearOfBirth = yearOfBirth;
	}

	/**
	* Getter for the name.
	**/
	public String getName()
	{
		return name;
	}

	/**
	* Getter for the year of birth.
	**/
	public int getYearOfBirth()
	{
		return yearOfBirth;
	}
}

public interface Reservable
{
	boolean isReserved();

	void reserve();

	void cancelReservation();
}

public class HotelRoom implements Reservable, Comparable<HotelRoom>
{
	private final int roomNumber;
	private final boolean reserved;

	public HotelRoom(final int roomNumber)
	{
		this.roomNumber = roomNumber;
		this.reserved = false;
	}

	@Override
	public boolean isReserved()
	{
		return reserved;
	}

	@Override
	public void reserve()
	{
		reserved = true;
	}

	@Override
	public void cancelReservation()
	{
		reserved = false;
	}

	@Override
	public int compareTo(final HotelRoom other)
	{
		return Integer.compare(this.roomNumber, other.roomNumber);
	}
}
